import { homedir } from 'node:os'
import { join, resolve } from 'node:path'

export function generateId(): string {
    return crypto.randomUUID()
}

export function delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms))
}

export function debounce<T extends (...args: unknown[]) => unknown>(fn: T, ms: number): T {
    let timer: NodeJS.Timeout
    return ((...args: unknown[]) => {
        clearTimeout(timer)
        timer = setTimeout(() => fn(...args), ms)
    }) as T
}

export function throttle<T extends (...args: unknown[]) => unknown>(fn: T, ms: number): T {
    let lastCall = 0
    return ((...args: unknown[]) => {
        const now = Date.now()
        if (now - lastCall >= ms) {
            lastCall = now
            return fn(...args)
        }
    }) as T
}

export function formatBytes(bytes: number, decimals = 2): string {
    if (bytes === 0) return '0 Bytes'
    const k = 1024
    const dm = Math.max(0, decimals)
    const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB', 'PB']
    const i = Math.floor(Math.log(bytes) / Math.log(k))
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(dm))} ${sizes[i]}`
}

export function formatMemoryUsage(): Record<string, string> {
    const m = process.memoryUsage()
    return {
        rss: formatBytes(m.rss),
        heapUsed: formatBytes(m.heapUsed),
        heapTotal: formatBytes(m.heapTotal),
        external: formatBytes(m.external),
    }
}

export function formatDuration(ms: number): string {
    if (ms < 1000) return `${ms}ms`
    if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`
    if (ms < 3_600_000) return `${(ms / 60_000).toFixed(1)}m`
    return `${(ms / 3_600_000).toFixed(1)}h`
}

export function deepMerge<
    T extends Record<string, unknown>,
    U extends Record<string, unknown>,
>(target: T, source: U): T & U {
    const result = { ...target } as Record<string, unknown>
    for (const key in source) {
        if (!Object.prototype.hasOwnProperty.call(source, key)) continue
        const src = source[key]
        const dst = result[key]

        if (src === null || src === undefined) {
            result[key] = src
        } else if (typeof src === 'object' && !Array.isArray(src)) {
            result[key] = deepMerge(
                dst && typeof dst === 'object' && !Array.isArray(dst) ? dst as Record<string, unknown> : {},
                src as Record<string, unknown>,
            )
        } else {
            result[key] = src
        }
    }
    return result as T & U
}

export function mergeInPlace(target: Record<string, unknown>, source: Record<string, unknown>): void {
    for (const key of Object.keys(source)) {
        const val = source[key]
        if (val != null && typeof val === 'object' && !Array.isArray(val)) {
            if (!target[key] || typeof target[key] !== 'object' || Array.isArray(target[key])) {
                target[key] = {}
            }
            mergeInPlace(target[key] as Record<string, unknown>, val as Record<string, unknown>)
        } else {
            target[key] = val
        }
    }
}

export function resolveWorkspaceDir(dir: string | undefined): string {
    if (!dir?.trim()) return process.cwd()
    const s = dir.trim()
    const expanded = s.startsWith('~') ? join(homedir(), s.slice(1)) : s
    return resolve(expanded)
}

export class PathResolver {
    static resolve(path: string, basePath?: string): string {
        if (path.startsWith('~')) return resolve(homedir(), path.slice(1))
        if (path.startsWith('/')) return resolve(path)
        return resolve(basePath || process.cwd(), path)
    }

    static resolveMultiple(paths: string[], basePath?: string): string[] {
        return paths.map((p) => this.resolve(p, basePath))
    }
}

export class RetryHandler {
    static async retry<T>(
        fn: () => Promise<T>,
        options: {
            maxRetries?: number
            delay?: number
            backoff?: number
            onRetry?: (attempt: number, error: Error) => void
        } = {},
    ): Promise<T> {
        const { maxRetries = 3, delay: retryDelay = 1000, backoff = 2, onRetry } = options
        let lastError: Error

        for (let attempt = 0; attempt <= maxRetries; attempt++) {
            try {
                return await fn()
            } catch (error) {
                lastError = error as Error
                if (attempt === maxRetries) break
                onRetry?.(attempt + 1, lastError)
                await new Promise((resolve) =>
                    setTimeout(resolve, retryDelay * Math.pow(backoff, attempt)),
                )
            }
        }

        throw lastError!
    }
}
