/**
 * Centralized error codes, error class, and factory for consistent error handling.
 */

export class NovaClawError extends Error {
    public readonly code: string
    public readonly details?: unknown

    constructor(message: string, code: string, details?: unknown) {
        super(message)
        this.name = 'NovaClawError'
        this.code = code
        this.details = details
    }
}

export const ErrorCodes = {
    CONFIG_INVALID: 'CONFIG_INVALID',
    CONFIG_LOAD_FAILED: 'CONFIG_LOAD_FAILED',
    INIT_FAILED: 'INIT_FAILED',
    PROTOCOL_ERROR: 'PROTOCOL_ERROR',
    CHANNEL_NOT_FOUND: 'CHANNEL_NOT_FOUND',
    VALIDATION_ERROR: 'VALIDATION_ERROR',
    SERVICE_UNAVAILABLE: 'SERVICE_UNAVAILABLE',
    AUTH_ERROR: 'AUTH_ERROR',
    NOT_FOUND: 'NOT_FOUND',
    NOT_IMPLEMENTED: 'NOT_IMPLEMENTED',
    INTERNAL_ERROR: 'INTERNAL_ERROR',

    // Provider layer
    PROVIDER_UNAVAILABLE: 'PROVIDER_UNAVAILABLE',
    PROVIDER_RATE_LIMITED: 'PROVIDER_RATE_LIMITED',
    PROVIDER_AUTH_FAILED: 'PROVIDER_AUTH_FAILED',
    PROVIDER_MODEL_NOT_FOUND: 'PROVIDER_MODEL_NOT_FOUND',
    PROVIDER_TIMEOUT: 'PROVIDER_TIMEOUT',

    // Tool layer
    TOOL_EXECUTION_FAILED: 'TOOL_EXECUTION_FAILED',
    TOOL_NOT_FOUND: 'TOOL_NOT_FOUND',
    TOOL_TIMEOUT: 'TOOL_TIMEOUT',
    TOOL_VALIDATION_FAILED: 'TOOL_VALIDATION_FAILED',

    // Agent layer
    AGENT_MAX_TURNS: 'AGENT_MAX_TURNS',
    AGENT_EXECUTION_FAILED: 'AGENT_EXECUTION_FAILED',
    AGENT_FALLBACK_EXHAUSTED: 'AGENT_FALLBACK_EXHAUSTED',

    // Session
    SESSION_NOT_FOUND: 'SESSION_NOT_FOUND',
    SESSION_EXPIRED: 'SESSION_EXPIRED',
} as const

export type ErrorCode = (typeof ErrorCodes)[keyof typeof ErrorCodes]

export function createError(
    message: string,
    code: ErrorCode,
    details?: unknown,
): NovaClawError {
    return new NovaClawError(message, code, details)
}

/**
 * Safely extract an error message from an unknown thrown value.
 * Prefer this over `(err as Error).message` for type safety.
 */
export function toErrorMessage(err: unknown): string {
    return err instanceof Error ? err.message : String(err)
}

/**
 * Extract error name from an unknown thrown value (useful for AbortError checks).
 */
export function toErrorName(err: unknown): string {
    return err instanceof Error ? err.name : ''
}

/** Map an HTTP status code from an LLM API error to the most appropriate ErrorCode. */
export function providerErrorCode(statusCode: number): ErrorCode {
    switch (statusCode) {
        case 401:
        case 403:
            return ErrorCodes.PROVIDER_AUTH_FAILED
        case 404:
            return ErrorCodes.PROVIDER_MODEL_NOT_FOUND
        case 408:
            return ErrorCodes.PROVIDER_TIMEOUT
        case 429:
            return ErrorCodes.PROVIDER_RATE_LIMITED
        default:
            return ErrorCodes.PROVIDER_UNAVAILABLE
    }
}
