/**
 * Structured logger backed by tslog.
 *
 * Caller-location display (file + line) is a native tslog feature,
 * controlled globally via {@link Logger.enableCallerInfo} — typically
 * driven by `config.logging.showCaller` at application startup.
 */

import { Logger as TsLog, type ILogObj } from 'tslog'

export interface ILogger {
    debug(message: string, data?: unknown): void
    info(message: string, data?: unknown): void
    warn(message: string, data?: unknown): void
    error(message: string, error?: unknown): void
}

const LEVEL_MAP: Record<string, number> = {
    debug: 2,
    info: 3,
    warn: 4,
    error: 5,
}

export class Logger implements ILogger {
    private static _showCaller = false
    private readonly _log: TsLog<ILogObj>

    /**
     * Turn caller-location tagging on/off for all Logger instances.
     * Call once at startup; the setting is intentionally global because
     * source-location display is a cross-cutting debugging concern.
     */
    static enableCallerInfo(enabled: boolean): void {
        Logger._showCaller = enabled
    }

    constructor(component: string, level = 'info') {
        this._log = new TsLog<ILogObj>({
            name: component,
            minLevel: LEVEL_MAP[level] ?? LEVEL_MAP.info,
            hideLogPositionForProduction: !Logger._showCaller,
            stylePrettyLogs: true,
        })
    }

    debug(message: string, data?: unknown): void {
        this.syncCallerSetting()
        if (data !== undefined) this._log.debug(message, data)
        else this._log.debug(message)
    }

    info(message: string, data?: unknown): void {
        this.syncCallerSetting()
        if (data !== undefined) this._log.info(message, data)
        else this._log.info(message)
    }

    warn(message: string, data?: unknown): void {
        this.syncCallerSetting()
        if (data !== undefined) this._log.warn(message, data)
        else this._log.warn(message)
    }

    error(message: string, error?: unknown): void {
        this.syncCallerSetting()
        if (error !== undefined) this._log.error(message, error)
        else this._log.error(message)
    }

    /**
     * Keeps the tslog instance in sync with the global showCaller flag.
     * Handles loggers created before {@link enableCallerInfo} is called
     * (e.g. static class-level properties).
     */
    private syncCallerSetting(): void {
        this._log.settings.hideLogPositionForProduction = !Logger._showCaller
    }
}
